/**
 * escher-fba.min.js
 * =================
 * Implements the escherFba interface expected by escher-FBA_code3_2.js:
 *
 *   escherFba.loadModel(xmlString)         → model object
 *   model.setUpperBound(reactionId, value) → void
 *   escherFba.solve(model, solver)         → { objectiveValue, fluxes, status }
 *
 * Uses glpk.js (loaded as ES module, exposed as window.glpk) for LP solving.
 */

const escherFba = (function () {

    const FBC_NS = 'http://www.sbml.org/sbml/level3/version1/fbc/version2';

    // Helper: get attribute trying both namespaced and plain forms
    function getAttr(el, localName) {
        return el.getAttributeNS(FBC_NS, localName)
            || el.getAttribute('fbc:' + localName)
            || el.getAttribute(localName)
            || null;
    }

    // ── SBML parser ───────────────────────────────────────────────────────────
    function parseModel(xmlString) {
        const parser = new DOMParser();
        const doc    = parser.parseFromString(xmlString, 'application/xml');

        const parseError = doc.querySelector('parsererror');
        if (parseError) throw new Error('SBML parse error: ' + parseError.textContent.slice(0, 300));

        // ── Species ───────────────────────────────────────────────────────────
        const speciesMap = {};
        doc.querySelectorAll('listOfSpecies > species').forEach(s => {
            speciesMap[s.getAttribute('id')] = {
                id:          s.getAttribute('id'),
                name:        s.getAttribute('name') || s.getAttribute('id'),
                compartment: s.getAttribute('compartment'),
            };
        });

        // ── fbc:fluxBound elements (SBML L3 FBC v1 style) ────────────────────
        const fbcBounds = {};
        doc.querySelectorAll('fluxBound').forEach(fb => {
            const rxn = fb.getAttribute('reaction');
            const op  = fb.getAttribute('operation') || 'lessEqual';
            const val = parseFloat(fb.getAttribute('value'));
            if (!fbcBounds[rxn]) fbcBounds[rxn] = {};
            if (op === 'greaterEqual' || op === 'greaterThanOrEqual') fbcBounds[rxn].lb = val;
            if (op === 'lessEqual'    || op === 'lessThanOrEqual')    fbcBounds[rxn].ub = val;
            if (op === 'equal')       { fbcBounds[rxn].lb = val; fbcBounds[rxn].ub = val; }
        });

        // ── Reactions ─────────────────────────────────────────────────────────
        const reactions    = [];
        const reactionIndex = {};

        doc.querySelectorAll('listOfReactions > reaction').forEach(r => {
            const id  = r.getAttribute('id');
            const rev = r.getAttribute('reversible') !== 'false';

            // Stoichiometry
            const stoich = {};
            r.querySelectorAll('listOfReactants > speciesReference').forEach(sr => {
                const sp = sr.getAttribute('species');
                const st = parseFloat(sr.getAttribute('stoichiometry') || '1');
                if (sp) stoich[sp] = (stoich[sp] || 0) - st;
            });
            r.querySelectorAll('listOfProducts > speciesReference').forEach(sr => {
                const sp = sr.getAttribute('species');
                const st = parseFloat(sr.getAttribute('stoichiometry') || '1');
                if (sp) stoich[sp] = (stoich[sp] || 0) + st;
            });

            // Bounds — fbc:listOfFluxBounds > fbc: attributes on reaction > defaults
            let lb = fbcBounds[id]?.lb;
            let ub = fbcBounds[id]?.ub;

            if (lb === undefined) {
                const lbStr = getAttr(r, 'lowerFluxBound');
                lb = lbStr !== null ? parseFloat(lbStr) : (rev ? -1000 : 0);
            }
            if (ub === undefined) {
                const ubStr = getAttr(r, 'upperFluxBound');
                ub = ubStr !== null ? parseFloat(ubStr) : 1000;
            }

            const rxn = { id, stoich, lb, ub, _origLb: lb, _origUb: ub };
            reactions.push(rxn);
            reactionIndex[id] = rxn;
        });

        // ── Objective function ────────────────────────────────────────────────
        let objectiveReactions = {};

        // Try fbc:listOfObjectives (FBC v2, namespaced)
        const objEls = doc.querySelectorAll('listOfObjectives objective, objective');
        objEls.forEach(obj => {
            obj.querySelectorAll('listOfFluxObjectives > fluxObjective, fluxObjective').forEach(fo => {
                const rxn  = getAttr(fo, 'reaction') || fo.getAttribute('reaction');
                const coef = parseFloat(getAttr(fo, 'coefficient') || fo.getAttribute('coefficient') || '1');
                if (rxn) objectiveReactions[rxn] = coef;
            });
        });

        // Fallback: biomass reaction by ID
        if (Object.keys(objectiveReactions).length === 0) {
            const biomassRxn = reactions.find(r => /biomass/i.test(r.id) || /growth/i.test(r.id));
            if (biomassRxn) {
                objectiveReactions[biomassRxn.id] = 1;
                console.log('[escherFba] Objective fallback: using', biomassRxn.id);
            }
        }

        // Last resort: last reaction
        if (Object.keys(objectiveReactions).length === 0 && reactions.length > 0) {
            const last = reactions[reactions.length - 1];
            objectiveReactions[last.id] = 1;
            console.warn('[escherFba] No objective found — using last reaction:', last.id);
        }

        console.log('[escherFba] Model loaded —',
            reactions.length, 'reactions,',
            Object.keys(speciesMap).length, 'species,',
            'objective:', Object.keys(objectiveReactions));

        return {
            reactions,
            reactionIndex,
            speciesMap,
            objectiveReactions,

            setUpperBound(reactionId, value) {
                const rxn = this.reactionIndex[reactionId];
                if (rxn) rxn.ub = value;
                else console.debug('[escherFba] setUpperBound: not found —', reactionId);
            },

            setLowerBound(reactionId, value) {
                const rxn = this.reactionIndex[reactionId];
                if (rxn) rxn.lb = value;
            },

            reset() {
                this.reactions.forEach(r => { r.lb = r._origLb; r.ub = r._origUb; });
            },
        };
    }

    // ── FBA solver ────────────────────────────────────────────────────────────
    // Helper: initialise glpk with pre-fetched WASM if available
    async function initGlpk() {
        const factory = window.glpk;
        if (!factory) throw new Error('glpk factory not loaded');
        const opts = window._glpkWasmBinary ? { wasmBinary: window._glpkWasmBinary } : {};
        return await factory(opts);
    }

    function solve(model, solver) {
        const { reactions, speciesMap, objectiveReactions } = model;

        if (reactions.length === 0) {
            console.warn('[escherFba] No reactions — returning zero objective');
            return { objectiveValue: 0, fluxes: {}, status: 'empty' };
        }

        // Objective
        const objVars = [];
        reactions.forEach(r => {
            const coef = objectiveReactions[r.id] || 0;
            if (coef !== 0) objVars.push({ name: r.id, coef });
        });

        const obj = { direction: solver.GLP_MAX, name: 'obj', vars: objVars };

        // Mass balance constraints (only for species that appear in stoichiometry)
        const subjectTo = [];
        const speciesIds = Object.keys(speciesMap);

        // If no species defined, skip mass balance (unconstrained model)
        if (speciesIds.length > 0) {
            speciesIds.forEach(spId => {
                const vars = [];
                reactions.forEach(r => {
                    const s = r.stoich[spId];
                    if (s && s !== 0) vars.push({ name: r.id, coef: s });
                });
                if (vars.length > 0) {
                    subjectTo.push({
                        name: 'mb_' + spId,
                        vars,
                        bnds: { type: solver.GLP_FX, ub: 0, lb: 0 },
                    });
                }
            });
        }

        // Variable bounds
        const bounds = reactions.map(r => {
            let type;
            const lb = isFinite(r.lb) ? r.lb : -1e30;
            const ub = isFinite(r.ub) ? r.ub :  1e30;
            if (lb === ub)                        type = solver.GLP_FX;
            else if (isFinite(r.lb) && isFinite(r.ub)) type = solver.GLP_DB;
            else if (isFinite(r.lb))              type = solver.GLP_LO;
            else if (isFinite(r.ub))              type = solver.GLP_UP;
            else                                  type = solver.GLP_FR;
            return { name: r.id, type, lb, ub };
        });

        const lp = { name: 'GEMgen_FBA', objective: obj, subjectTo, bounds };

        let result;
        try {
            result = solver.solve(lp, { msglev: solver.GLP_MSG_OFF });
        } catch (e) {
            console.error('[escherFba] glpk solve error:', e);
            return { objectiveValue: 0, fluxes: {}, status: 'error' };
        }

        const z      = result?.result?.z     ?? 0;
        const vars   = result?.result?.vars  ?? {};
        const status = result?.result?.status ?? 0;

        const isOpt = status === 5 || status === solver.GLP_OPT;
        if (!isOpt) console.warn('[escherFba] Non-optimal status:', status);

        console.log('[escherFba] FBA solved — objective:', z.toFixed(6), '| status:', status);

        return {
            objectiveValue: z,
            fluxes:         vars,
            status:         isOpt ? 'optimal' : 'non-optimal',
        };
    }

    return { loadModel: parseModel, solve };

})();
